<span class="line">        r<span class="token punctuation">.</span>Response<span class="token punctuation">.</span><span class="token function">Write</span><span class="token punctuation">(</span><span class="token string">&quot;用户ID:&quot;</span><span class="token punctuation">,</span> uid<span class="token punctuation">)</span></span>
